#include<bits/stdc++.h>
using namespace std;
const long long mod=1e9+7;
long long fastpow(long long x,long long y)
{
    x%=mod;
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
long long f(long long v,long long x)
{
    return ((fastpow(v,x*2)-fastpow(v,x)+fastpow(v,x-1))%mod+mod)%mod;
}
struct node
{
    long long c,d;
    bool operator<(const node&b)const
    {
        if(c==b.c)
        {
            return d<b.d;
        }
        return c<b.c;
    }
}a[100010];
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long n,m,v;
        scanf("%lld%lld%lld",&n,&m,&v);
        for(long long i=1;i<=m;i++)
        {
            scanf("%lld%lld",&a[i].c,&a[i].d);
        }
        sort(a+1,a+1+m);
        long long ans=1;
        for(long long i=2;i<=m;i++)
        {
            long long len=a[i].c-a[i-1].c;
            if(len==0)
            {
                if(a[i].d==a[i-1].d)
                {
                    continue;
                }
                else
                {
                    ans=0;
                    break;
                }
            }
            ans*=f(v,len);
            ans%=mod;
        }
        ans*=fastpow(v,(a[1].c-1)*2);
        ans%=mod;
        ans*=fastpow(v,(n-a[m].c)*2);
        ans%=mod;
        printf("%lld\n",ans);
    }
    return 0;
}
